namespace sv_020bd9098b30481b988392e740719577.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public Theme Theme { get; set; } = Theme.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

using Microsoft.AspNetCore.Components;

namespace sv_020bd9098b30481b988392e740719577.Services;

/// <summary>
/// Scoped service that wraps CascadingValueSource&lt;ThemeInfo&gt; so any
/// interactive component can read/write theme state and push updates
/// to every subscriber — including static-SSR layout components.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
    }

    public ThemeInfo Current { get; private set; } = new();

    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        Current.Theme = theme;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string accentColor)
    {
        Current.AccentColor = accentColor;
        await NotifyAsync();
    }

    public async Task UpdateAsync(Theme theme, string accentColor)
    {
        Current.Theme = theme;
        Current.AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        // Push to all [CascadingParameter] subscribers (including static layout)
        await _source.NotifyChangedAsync(Current);
        // Also fire event for components using the service directly
        OnChange?.Invoke();
    }
}

