arguments.file_text:
@* Displays current theme in the layout header. Works in static SSR
   because it reads from CascadingValueSource via [CascadingParameter]. *@

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetIcon() @Theme?.Theme
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetIcon() => Theme?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            var isActive = t == _selectedTheme;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SelectTheme(t)">
                @t
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accent">Accent Color</label>
    <input id="accent" type="color" class="form-control form-control-color"
           value="@_accentColor" @onchange="AccentChanged" />
</div>

<div class="alert mt-4" style="border-left: 4px solid @_accentColor;">
    Preview — accent color: <strong style="color: @_accentColor;">@_accentColor</strong>,
    theme: <strong>@_selectedTheme</strong>
</div>

@code {
    private Theme _selectedTheme;
    private string _accentColor = "#0d6efd";

    [CascadingParameter]
    private ThemeInfo? ThemeInfo { get; set; }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
        SyncFromCascading();
    }

    protected override void OnParametersSet()
    {
        SyncFromCascading();
    }

    private void SyncFromCascading()
    {
        if (ThemeInfo is not null)
        {
            _selectedTheme = ThemeInfo.Theme;
            _accentColor = ThemeInfo.AccentColor;
        }
    }

    private async Task SelectTheme(Theme theme)
    {
        _selectedTheme = theme;
        await ThemeService.UpdateAsync(_selectedTheme, _accentColor);
    }

    private async Task AccentChanged(ChangeEventArgs e)
    {
        _accentColor = e.Value?.ToString() ?? _accentColor;
        await ThemeService.UpdateAsync(_selectedTheme, _accentColor);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

